const applyFontSizes = (fontSizes = {}) => {
  const globalScale = (fontSizes.global || 100) / 100;
  document.documentElement.style.fontSize = (16 * globalScale) + 'px';
  const styleId = 'dynamic-font-sizes';
  let styleEl = document.getElementById(styleId);
  if (!styleEl) {
    styleEl = document.createElement('style');
    styleEl.id = styleId;
    document.head.appendChild(styleEl);
  }
  const areas = ['header', 'dashboard', 'tables', 'settings'];
  const rules = areas.map(area => {
    const scale = (fontSizes[area] || 100) / 100;
    if (scale === 1) return '';
    return `[data-fs="${area}"] { zoom: ${scale}; }`;
  }).filter(Boolean);
  // execution: zoom on the fixed container, but compensate dimensions so it stays within viewport
  const execScale = (fontSizes.execution || 100) / 100;
  if (execScale !== 1) {
    rules.push(`[data-fs="execution"] { zoom: ${execScale}; width: ${100 / execScale}vw; height: ${100 / execScale}vh; left: 0; top: 0; transform-origin: top left; }`);
  }
  // measurement: 測定モーダル専用 (最大化時の文字サイズ)
  const measScale = (fontSizes.measurement || 100) / 100;
  if (measScale !== 1) {
    rules.push(`[data-fs="measurement"] { zoom: ${measScale}; width: ${100 / measScale}vw; height: ${100 / measScale}vh; left: 0; top: 0; transform-origin: top left; }`);
  }
  styleEl.textContent = rules.join('\n');
};

// --- Utilities ---
// 衝突防止: crypto.randomUUID 利用可能ならそれを使う、なければ Math.random.
// substr は deprecated なので slice を使用
const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID().replace(/-/g, '').slice(0, 12);
    }
  } catch {}
  return Math.random().toString(36).slice(2, 11) + Math.random().toString(36).slice(2, 5);
};
const formatTime = (sec) => {
  // NaN/undefined/null/負数 を安全にハンドル (旧データ修復時の表示崩れ防止)
  const n = Number(sec);
  if (!Number.isFinite(n) || n < 0) return '0:00';
  const h = Math.floor(n / 3600);
  const m = Math.floor((n % 3600) / 60);
  const s = Math.floor(n % 60);
  if (h > 0) return `${h}:${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
  return `${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
};
const toDatetimeLocal = (timestamp) => {
  const d = new Date(timestamp);
  const pad = (n) => n.toString().padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
};
const toDateShort = (timestamp) => {
  if (!timestamp) return '-';
  const d = new Date(timestamp);
  return `${d.getMonth()+1}/${d.getDate()}`;
};
const formatDateSafe = (ts) => ts ? new Date(ts).toLocaleString() : '-';

const resizeImage = (file) => new Promise((resolve) => { const r = new FileReader(); r.onload = (e) => { const i = new Image(); i.onload = () => { const c = document.createElement('canvas'); const MAX = 1000; let w=i.width; let h=i.height; if(w>h){if(w>MAX){h*=MAX/w;w=MAX}}else{if(h>MAX){w*=MAX/h;h=MAX}} c.width=w; c.height=h; const ctx=c.getContext('2d'); if(ctx){ctx.drawImage(i,0,0,w,h); resolve(c.toDataURL('image/jpeg', 0.7));}else resolve(i.src); }; i.src = e.target?.result; }; r.readAsDataURL(file); });
const getBase64 = (file) => new Promise((resolve) => { const r = new FileReader(); r.readAsDataURL(file); r.onload = () => resolve(r.result); r.onerror = () => resolve(""); });

// === 時間ソース一本化 (2026-05-31) ===
// 「工程改善・目標時間最適化」タブが算出した較正値 (settings.customTargetTimes) を
// 実際の目標時間として使うための単一ヘルパー。
// 優先順位: 型式別較正値 (customTargetTimes[model_型式][category_title]) > step.targetTime (テンプレ既定)
//
// キー形式 (ProcessInsightsTab と一致させる):
//   savedKey = `model_${model}`
//   stepKey  = `${step.category || ''}_${step.title}`
const targetTimeStepKey = (step) => `${step?.category || ''}_${step?.title || ''}`;
const getEffectiveTargetTime = (step, model, customTargetTimes) => {
  if (!step) return 0;
  const fallback = step.targetTime || 0;
  if (!model || !customTargetTimes) return fallback;
  const calibrated = customTargetTimes[`model_${model}`]?.[targetTimeStepKey(step)];
  return (typeof calibrated === 'number' && calibrated > 0) ? calibrated : fallback;
};

// ロットの推定総時間。customTargetTimes があれば型式別較正値を使う。
const calculateLotEstimatedTime = (lot, customTargetTimes = null) => {
  if (!lot?.steps || !Array.isArray(lot.steps)) return 0;
  const perUnitTime = lot.steps.reduce((sum, step) => sum + getEffectiveTargetTime(step, lot.model, customTargetTimes), 0);
  return perUnitTime * (lot.quantity || 1);
};

// === 勤務時間マスタ ===
// ユーザ会社の実態に合わせたデフォルト勤務スケジュール:
//  - 8:30 始業 → 10:00 (休憩 10分) → 12:00 (休憩 45分) → 15:00 (休憩 15分) → 17:00 定時
//  - 17:00 → 17:15 (休憩 15分) → 17:15 → 19:15 残業終わり
// 実働: 8:30〜17:00 = 8.5h - 休憩 1.166h = 7.333h (定時)
//       残業 17:15〜19:15 = 2h → 合計 9.333h (残業込み)
const DEFAULT_WORK_SCHEDULE = {
  dayStart: '08:30',
  dayEnd: '17:00',           // 定時終わり
  overtimeStart: '17:15',    // 残業開始 (定時終わり後の休憩明け)
  overtimeEnd: '19:15',      // 残業終わり (=2時間残業を想定)
  breaks: [
    { start: '10:00', end: '10:10', name: '10時休憩' },
    { start: '12:00', end: '12:45', name: '昼休憩' },
    { start: '15:00', end: '15:15', name: '15時休憩' },
    { start: '17:00', end: '17:15', name: '残業前休憩' },
  ],
  daysPerWeek: 5,
  daysPerMonth: 20,
  includeOvertimeInCapacity: false, // 負荷計算に残業時間を含めるか (デフォルトは定時のみ)
};

// "HH:MM" を当日 0:00 からの分数に変換
const timeStrToMinutes = (str) => {
  if (!str || typeof str !== 'string') return 0;
  const [h, m] = str.split(':').map(Number);
  if (isNaN(h) || isNaN(m)) return 0;
  return h * 60 + m;
};

// 区間 [aStart, aEnd] と [bStart, bEnd] の重なり (分) を返す
const overlapMinutes = (aStart, aEnd, bStart, bEnd) => {
  const s = Math.max(aStart, bStart);
  const e = Math.min(aEnd, bEnd);
  return Math.max(0, e - s);
};

// 2つのタイムスタンプ間の「勤務時間内」だけの経過時間を秒で返す。
// 会社外時間 (夜間/休憩中/土日) はカウントしない。
//   schedule.daysPerWeek <= 5 の場合は土日除外
//   includeOvertime=true で残業時間 (19:15まで) も含める
const computeElapsedWorkSeconds = (startMs, endMs, schedule, includeOvertime = true) => {
  if (!startMs || !endMs || endMs <= startMs) return 0;
  const sch = { ...DEFAULT_WORK_SCHEDULE, ...(schedule || {}) };
  const dayStartMin = timeStrToMinutes(sch.dayStart);
  // 残業込みなら overtimeEnd まで、定時のみなら dayEnd まで
  const dayEndMin = (includeOvertime && sch.overtimeEnd) ? timeStrToMinutes(sch.overtimeEnd) : timeStrToMinutes(sch.dayEnd);
  const breaks = (sch.breaks || []).map(b => ({ start: timeStrToMinutes(b.start), end: timeStrToMinutes(b.end) }));
  const excludeWeekend = (sch.daysPerWeek || 5) <= 5;

  let totalSec = 0;
  // 日付ループ
  const startDate = new Date(startMs);
  const endDate = new Date(endMs);
  const cursor = new Date(startDate.getFullYear(), startDate.getMonth(), startDate.getDate());
  const lastDay = new Date(endDate.getFullYear(), endDate.getMonth(), endDate.getDate());

  while (cursor.getTime() <= lastDay.getTime()) {
    const dow = cursor.getDay();
    if (excludeWeekend && (dow === 0 || dow === 6)) {
      cursor.setDate(cursor.getDate() + 1);
      continue;
    }
    // この日の勤務時間レンジ (ms)
    const dayWorkStart = new Date(cursor); dayWorkStart.setHours(0, dayStartMin, 0, 0);
    const dayWorkEnd = new Date(cursor); dayWorkEnd.setHours(0, dayEndMin, 0, 0);
    // 計測範囲との重なり
    const overlapStart = Math.max(startMs, dayWorkStart.getTime());
    const overlapEnd = Math.min(endMs, dayWorkEnd.getTime());
    if (overlapEnd > overlapStart) {
      let overlapMs = overlapEnd - overlapStart;
      // 重なった範囲内の休憩を差し引く
      for (const b of breaks) {
        const breakStart = new Date(cursor); breakStart.setHours(0, b.start, 0, 0);
        const breakEnd = new Date(cursor); breakEnd.setHours(0, b.end, 0, 0);
        const bOverlap = Math.max(0, Math.min(overlapEnd, breakEnd.getTime()) - Math.max(overlapStart, breakStart.getTime()));
        overlapMs -= bOverlap;
      }
      totalSec += Math.max(0, overlapMs) / 1000;
    }
    cursor.setDate(cursor.getDate() + 1);
  }
  return Math.floor(totalSec);
};

// 勤務スケジュールから「1 日の実働時間」を計算 (分単位)
// 戻り値: { regularMinutes, overtimeMinutes, totalMinutes, regularHours, overtimeHours, totalHours }
const computeWorkHours = (schedule) => {
  const sch = { ...DEFAULT_WORK_SCHEDULE, ...(schedule || {}) };
  const dayStart = timeStrToMinutes(sch.dayStart);
  const dayEnd = timeStrToMinutes(sch.dayEnd);
  const overtimeStart = timeStrToMinutes(sch.overtimeStart);
  const overtimeEnd = timeStrToMinutes(sch.overtimeEnd);
  const breaks = (sch.breaks || []).map(b => ({ start: timeStrToMinutes(b.start), end: timeStrToMinutes(b.end) }));

  // 定時内の実働: dayStart 〜 dayEnd の総時間から、その期間と重なる休憩を引く
  const regularSpan = Math.max(0, dayEnd - dayStart);
  const regularBreakMin = breaks.reduce((acc, b) => acc + overlapMinutes(b.start, b.end, dayStart, dayEnd), 0);
  const regularMinutes = Math.max(0, regularSpan - regularBreakMin);

  // 残業時間の実働: overtimeStart 〜 overtimeEnd の総時間から、その期間と重なる休憩を引く
  let overtimeMinutes = 0;
  if (overtimeEnd > overtimeStart) {
    const overtimeSpan = overtimeEnd - overtimeStart;
    const overtimeBreakMin = breaks.reduce((acc, b) => acc + overlapMinutes(b.start, b.end, overtimeStart, overtimeEnd), 0);
    overtimeMinutes = Math.max(0, overtimeSpan - overtimeBreakMin);
  }

  const totalMinutes = regularMinutes + overtimeMinutes;
  return {
    regularMinutes,
    overtimeMinutes,
    totalMinutes,
    regularHours: regularMinutes / 60,
    overtimeHours: overtimeMinutes / 60,
    totalHours: totalMinutes / 60,
  };
};

// 「分」を "Xh Ymin" 形式に整形
const formatHoursMinutes = (totalMin) => {
  const h = Math.floor(totalMin / 60);
  const m = Math.round(totalMin % 60);
  if (h === 0) return `${m}分`;
  if (m === 0) return `${h}時間`;
  return `${h}時間${m}分`;
};

// === 品質規格 / 型式オーバーライドの適用 (共通ヘルパー) ===
// ロット作成・Excel 取込・編集 で共通利用するため切り出し。
// 優先順位:
//   1) modelStandardMap[model] にマッピングがあれば品質規格を適用 (overrides + conditions)
//      - 規格内に templateId に一致するエントリがあればそれを使用
//      - 一致するエントリが無ければ規格は適用せず legacy fallback へ
//   2) なければ legacy measurementOverrides[model] を適用
//   3) どちらも無ければ steps をそのまま返す
// 戻り値: { steps: 加工後の steps, appliedStandard: ロットに焼き付けるスナップショット | null }

// 規格の中の「テンプレートごと設定」一覧を取得 (新形式 + 旧形式の両方を吸収)
//   新形式: qs.templates = [{ templateId, measurementOverrides, measurementConditions }, ...]
//   旧形式: qs.templateId + qs.measurementOverrides + qs.measurementConditions (1 件のみ)
const getQsTemplateEntries = (qs) => {
  if (!qs) return [];
  if (Array.isArray(qs.templates) && qs.templates.length > 0) {
    // ...t で全フィールド (defaultValues / checklistItemsByStep / stepProfile 等) を保持する。
    return qs.templates.map(t => ({
      ...t,
      templateId: t.templateId || '',
      measurementOverrides: t.measurementOverrides || {},
      measurementConditions: t.measurementConditions || {},
    }));
  }
  if (qs.templateId) {
    return [{
      templateId: qs.templateId,
      measurementOverrides: qs.measurementOverrides || {},
      measurementConditions: qs.measurementConditions || {},
      ...(qs.defaultValues ? { defaultValues: qs.defaultValues } : {}),
      ...(qs.checklistItemsByStep ? { checklistItemsByStep: qs.checklistItemsByStep } : {}),
      ...(qs.stepProfile ? { stepProfile: qs.stepProfile } : {}),
    }];
  }
  return [];
};

const applyQualityStandardToSteps = (model, baseSteps, settings, templateId = null) => {
  if (!model || !baseSteps) return { steps: baseSteps, appliedStandard: null, naStepIds: [] };
  let steps = baseSteps;
  let appliedStandard = null;
  const naStepIds = []; // 型式別プロファイルで「該当なし」にする step.id (ロット生成時に自動スキップ)

  // 時間ソース一本化: 型式別較正済み目標時間 (customTargetTimes) を step.targetTime へ焼き付け。
  // どの規格パスを通っても適用されるよう、関数化して各 return 前に通す。
  const applyCalibratedTargets = (stepsArr) => {
    const ctt = settings?.customTargetTimes;
    if (!ctt || !model || !ctt[`model_${model}`]) return stepsArr;
    const modelCal = ctt[`model_${model}`];
    return stepsArr.map(s => {
      const cal = modelCal[`${s.category || ''}_${s.title || ''}`];
      if (typeof cal === 'number' && cal > 0 && cal !== s.targetTime) {
        return { ...s, targetTime: cal, targetTimeCalibrated: true };
      }
      return s;
    });
  };

  // 1) 品質規格マスタを優先
  const qsId = settings?.modelStandardMap?.[model];
  const qs = qsId ? settings?.qualityStandards?.[qsId] : null;
  if (qs) {
    // 規格内に対象テンプレートに一致するエントリがあるか探す
    const entries = getQsTemplateEntries(qs);
    // templateId 指定時: 完全一致を探す → 無ければ「templateId 未指定」のエントリにフォールバック
    // templateId 未指定時: 1 件だけのときに採用 (誤適用を避けるため、複数あるなら null)
    let entry;
    if (templateId) {
      entry = entries.find(e => e.templateId === templateId)
           || entries.find(e => !e.templateId); // 全テンプレ共通エントリがあれば使う
    } else {
      // templateId 未指定: 全テンプレ共通エントリを優先、無ければ 1件しかないときに採用
      entry = entries.find(e => !e.templateId)
           || (entries.length === 1 ? entries[0] : null);
    }

    if (entry) {
      const qsOverrides = entry.measurementOverrides || {};
      const qsConditions = entry.measurementConditions || {};
      const qsDefaults = entry.defaultValues || {};  // 初期値プリセット (型式群で共有)
      const qsChecklist = entry.checklistItemsByStep || {};  // 確認チェック上書き
      const qsProfile = entry.stepProfile || {};  // 型式別 工程プロファイル: { [stepId]: { enabled, description?, pdfData?, images?, targetTime? } }
      steps = steps.map(s => {
        let outStep = s;
        // 確認チェック項目の上書き (測定/非測定どちらでも適用)
        if (qsChecklist[s.id] && Array.isArray(qsChecklist[s.id])) {
          outStep = { ...outStep, checklistItems: qsChecklist[s.id] };
        }
        // 型式別 工程プロファイル: 該当なし(enabled=false) は naStepIds へ。詳細/PDF/写真/目標時間は型式別に上書き。
        const prof = qsProfile[s.id];
        if (prof) {
          if (prof.enabled === false) naStepIds.push(s.id);
          if (prof.description != null && prof.description !== '') outStep = { ...outStep, description: prof.description };
          if (prof.pdfData) outStep = { ...outStep, pdfData: prof.pdfData };
          if (Array.isArray(prof.images) && prof.images.length > 0) outStep = { ...outStep, images: prof.images };
          if (typeof prof.targetTime === 'number' && prof.targetTime > 0) outStep = { ...outStep, targetTime: prof.targetTime };
        }
        if (!s.measurementConfig) return outStep;
        let newCfg = s.measurementConfig;
        const stepOv = qsOverrides[s.id];
        if (stepOv) {
          const newCalcs = (newCfg.calculations || []).map(c => {
            const calcOv = stepOv[c.id];
            if (!calcOv) return c;
            return {
              ...c,
              ...(calcOv.nominal !== undefined ? { nominal: calcOv.nominal } : {}),
              ...(calcOv.toleranceUpper !== undefined ? { toleranceUpper: calcOv.toleranceUpper } : {}),
              ...(calcOv.toleranceLower !== undefined ? { toleranceLower: calcOv.toleranceLower } : {}),
              ...(calcOv.toleranceEnabled !== undefined ? { toleranceEnabled: calcOv.toleranceEnabled } : {})
            };
          });
          newCfg = { ...newCfg, calculations: newCalcs };
        }
        const cond = qsConditions[s.id];
        if (cond && ((cond.params && cond.params.length > 0) || cond.note)) {
          newCfg = { ...newCfg, conditionPreset: { params: cond.params || [], note: cond.note || '' } };
        }
        // 初期値プリセットを焼き付け (測定画面で「初期値を入力」ボタンとして使う)
        const defaults = qsDefaults[s.id];
        if (defaults && Object.keys(defaults).length > 0) {
          newCfg = { ...newCfg, qsDefaultValues: { ...defaults } };
        }
        return { ...outStep, measurementConfig: newCfg };
      });
      appliedStandard = {
        id: qs.id,
        standardNo: qs.standardNo || '',
        name: qs.name || '',
        revision: qs.revision || '',
        templateId: entry.templateId,
        appliedAt: Date.now(),
        source: 'qualityStandard',
      };
      return { steps: applyCalibratedTargets(steps), appliedStandard, naStepIds };
    }
    // 規格はあるがこのテンプレ用のエントリ無し → legacy にフォールバック
  }

  // 2) レガシー measurementOverrides
  const overrides = settings?.measurementOverrides?.[model];
  if (overrides && typeof overrides === 'object') {
    steps = steps.map(s => {
      const stepOv = overrides[s.id];
      if (!stepOv || !s.measurementConfig) return s;
      const newCalcs = (s.measurementConfig.calculations || []).map(c => {
        const calcOv = stepOv[c.id];
        if (!calcOv) return c;
        return {
          ...c,
          ...(calcOv.nominal !== undefined ? { nominal: calcOv.nominal } : {}),
          ...(calcOv.toleranceUpper !== undefined ? { toleranceUpper: calcOv.toleranceUpper } : {}),
          ...(calcOv.toleranceLower !== undefined ? { toleranceLower: calcOv.toleranceLower } : {}),
          ...(calcOv.toleranceEnabled !== undefined ? { toleranceEnabled: calcOv.toleranceEnabled } : {})
        };
      });
      return { ...s, measurementConfig: { ...s.measurementConfig, calculations: newCalcs } };
    });
    appliedStandard = {
      id: null,
      standardNo: '(レガシーオーバーライド)',
      name: '型式別オーバーライド',
      revision: '',
      appliedAt: Date.now(),
      source: 'legacyOverride',
    };
  }

  // 時間ソース一本化: 較正済み目標時間を焼き付け (規格なし/レガシーパス)
  return { steps: applyCalibratedTargets(steps), appliedStandard, naStepIds };
};

// 型式別プロファイルの「該当なし」工程を、ロット生成時に各台 skipped で事前生成する。
// 作業者は検査画面で「解除」して検査することも可能 (融通を残す)。
const buildProfileSkippedTasks = (steps, naStepIds, qty) => {
  const tasks = {};
  if (!Array.isArray(naStepIds) || naStepIds.length === 0) return tasks;
  const naSet = new Set(naStepIds);
  (steps || []).forEach(s => {
    if (!naSet.has(s.id)) return;
    for (let u = 0; u < (qty || 1); u++) {
      tasks[`${s.id}-${u}`] = { status: 'skipped', profileSkipped: true, duration: 0, startTime: null, firstStartTime: null, endTime: null, workerName: '規格(該当なし)' };
    }
  });
  return tasks;
};

// === 進捗・ETA・遅延の計算ヘルパー ===
// ロットの進捗状況を一元計算 (LotCard / ProgressOverview / 遅延アラート 共通利用)
const computeLotProgress = (lot) => {
  if (!lot || !lot.steps || lot.steps.length === 0) return null;

  const totalTasks = lot.steps.length * (lot.quantity || 1);
  let completedCount = 0;
  let totalCompletedDuration = 0;
  const tasks = lot.tasks || {};

  lot.steps.forEach((step, sIdx) => {
    for (let u = 0; u < (lot.quantity || 1); u++) {
      const t = (step.id && tasks[`${step.id}-${u}`]) || tasks[`${sIdx}-${u}`];
      if (t && (t.status === 'completed' || t.status === 'skipped')) {
        completedCount++;
        totalCompletedDuration += (t.duration || 0);
      }
    }
  });

  const progressPct = totalTasks > 0 ? Math.round((completedCount / totalTasks) * 100) : 0;
  const remainingTasks = totalTasks - completedCount;

  // 平均タスク時間 (完了済みタスクから算出、なければ targetTime ベース)
  let avgTaskTime;
  if (completedCount > 0) {
    avgTaskTime = totalCompletedDuration / completedCount;
  } else {
    const targetSum = lot.steps.reduce((s, st) => s + (st.targetTime || 60), 0);
    avgTaskTime = targetSum / lot.steps.length;
  }

  // 開始時刻 (Firestore Timestamp / number / undefined どれでも対応)
  // 「予測時間の開始」は 実際に作業を開始した時刻 (workStartTime) のみを使用する。
  // 入荷時刻や登録時刻をフォールバックに使うと、まだ着手していないロットでも
  // 過去の時刻が「開始」として表示されて紛らわしいため、未開始は 0 を返す。
  const toMs = (v) => { if (!v) return 0; if (typeof v === 'number') return v; if (v.seconds) return v.seconds * 1000; if (v.toMillis) return v.toMillis(); const t = new Date(v).getTime(); return isNaN(t) ? 0 : t; };
  const startMs = toMs(lot.workStartTime);

  // 予測完了時刻 (ETA)
  const remainingSec = remainingTasks * avgTaskTime;
  const etaMs = Date.now() + remainingSec * 1000;

  // 標準予定時刻 (targetTime ベースで純粋に算出された理想完了時刻)
  // 未開始の場合は「今すぐ着手した場合の理想完了時刻」を採用する
  const standardDurationSec = lot.steps.reduce((s, st) => s + (st.targetTime || 60), 0) * (lot.quantity || 1);
  const standardStartMs = startMs || Date.now();
  const standardEtaMs = standardStartMs + standardDurationSec * 1000;

  // 遅延判定: ETA が標準予定より 30分以上後なら warning, 1時間以上後なら critical
  const delayMs = etaMs - standardEtaMs;
  let delayLevel = 'ontime';
  if (delayMs > 60 * 60 * 1000) delayLevel = 'critical';
  else if (delayMs > 30 * 60 * 1000) delayLevel = 'warning';
  else if (delayMs < -10 * 60 * 1000) delayLevel = 'ahead';

  // 完了済みなら ETA は完了時刻、遅延なし
  const isCompleted = lot.status === 'completed' || lot.location === 'completed';
  if (isCompleted) {
    delayLevel = 'completed';
  }

  return {
    totalTasks, completedCount, progressPct, remainingTasks,
    avgTaskTime, startMs, etaMs, standardEtaMs, delayMs, delayLevel,
    isCompleted, isProcessing: lot.status === 'processing',
  };
};

// 時刻を HH:MM 形式で
const formatHHMM = (ms) => {
  if (!ms) return '--:--';
  const d = new Date(ms);
  return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
};

// 「作業中」判定の共通化: lot.status === 'processing' か、カスタムモードで個別タスクが processing
const checkLotProcessing = (lot) => {
  if (!lot) return false;
  if (lot.status === 'processing') return true;
  const tasks = lot.tasks || {};
  for (const k in tasks) {
    if (tasks[k] && tasks[k].status === 'processing') return true;
  }
  return false;
};

// 停止理由カテゴリ → 色/絵文字 マッピング (4箇所で重複していたものを共通化)
const PAUSE_REASON_COLOR_MAP = {
  waiting_lot:      { bg: 'bg-amber-100',  border: 'border-amber-300',  text: 'text-amber-800',  emoji: '🟡' },
  waiting_repair:   { bg: 'bg-orange-100', border: 'border-orange-300', text: 'text-orange-800', emoji: '🟠' },
  paused:           { bg: 'bg-rose-100',   border: 'border-rose-300',   text: 'text-rose-800',   emoji: '🔴' },
  waiting_parts:    { bg: 'bg-purple-100', border: 'border-purple-300', text: 'text-purple-800', emoji: '🟣' },
  waiting_decision: { bg: 'bg-blue-100',   border: 'border-blue-300',   text: 'text-blue-800',   emoji: '🔵' },
};
const PAUSE_REASON_FALLBACK_COLOR = { bg: 'bg-slate-100', border: 'border-slate-300', text: 'text-slate-700', emoji: '⏸' };
const getPauseReasonColor = (category) => PAUSE_REASON_COLOR_MAP[category] || PAUSE_REASON_FALLBACK_COLOR;

// --- Measurement Utilities ---
// 数式評価 (セキュリティ強化版)
// - 変数 ID は英数字・アンダースコアのみ許可
// - 置換後の式は許可文字 + e/E (指数表記) のみ
// - new Function は使わず、自前 RPN 評価でサンドボックス化
// (evaluateFormula, evalArith, BLOCK_GAUGE_PRESETS は ./measurement-utils.js に移動)

const calculateMeasurementResult = (values, config) => {
  const entries = config.inputs.map(inp => ({ id: inp.id, val: Number(values[inp.id]) })).filter(e => !isNaN(e.val) && values[e.id] !== '' && values[e.id] != null);
  if (entries.length === 0) return null;
  const nums = entries.map(e => e.val);
  switch (config.calculation) {
    case 'max-min': return Math.max(...nums) - Math.min(...nums);
    case 'sum': return nums.reduce((a, b) => a + b, 0);
    case 'average': return nums.reduce((a, b) => a + b, 0) / nums.length;
    case 'formula': return evaluateFormula(config.formula, values);
    case 'group-max-min': {
      const groups = {};
      entries.forEach(e => {
        const prefix = e.id.replace(/[0-9]/g, '');
        if (!groups[prefix]) groups[prefix] = [];
        groups[prefix].push(e.val);
      });
      const groupMaxMins = Object.values(groups).filter(g => g.length > 0).map(g => Math.max(...g) - Math.min(...g));
      if (groupMaxMins.length === 0) return null; // 空グループ → null (Math.max([]) は -Infinity を返すため)
      return Math.max(...groupMaxMins);
    }
    default: return null;
  }
};

const calculateSingleResult = (values, relevantInputs, calc) => {
  // 入力ID + 「前の計算結果のID」両方を受け取れるように
  // values オブジェクトには通常入力に加えて、計算済みの calcId → result も入っている前提
  const entries = relevantInputs.map(inp => ({ id: inp.id, val: Number(values[inp.id]) })).filter(e => !isNaN(e.val) && values[e.id] !== '' && values[e.id] != null);
  if (calc.method === 'formula') {
    // 数式は relevantInputs に依存しない (values に全てが入っているため)
    return evaluateFormula(calc.formula, values);
  }
  if (entries.length === 0) return null;
  const nums = entries.map(e => e.val);
  switch (calc.method) {
    case 'max-min': return Math.max(...nums) - Math.min(...nums);
    case 'sum': return nums.reduce((a, b) => a + b, 0);
    case 'average': return nums.reduce((a, b) => a + b, 0) / nums.length;
    case 'abs-max': return Math.max(...nums.map(n => Math.abs(n)));
    case 'diff': {
      // 2点間の差: 入力 ID 順で最初と最後の差
      if (nums.length < 2) return null;
      return nums[0] - nums[nums.length - 1];
    }
    case 'group-max-min': {
      // 各グループ内の最大-最小 → さらに最大
      const groups = {};
      entries.forEach(e => {
        const inp = relevantInputs.find(i => i.id === e.id);
        const key = groupKeyFor(inp || { id: e.id });
        if (!groups[key]) groups[key] = [];
        groups[key].push(e.val);
      });
      const groupMaxMins = Object.values(groups).filter(g => g.length > 0).map(g => Math.max(...g) - Math.min(...g));
      if (groupMaxMins.length === 0) return null; // 空グループ防止
      return Math.max(...groupMaxMins);
    }
    case 'rows-diff': {
      // 通りの差: 各グループの平均値同士の差 (グループ平均 max - グループ平均 min)
      // 例: A グループ平均 50.02, B グループ平均 50.05 → 0.03
      const groups = {};
      entries.forEach(e => {
        const inp = relevantInputs.find(i => i.id === e.id);
        const key = groupKeyFor(inp || { id: e.id });
        if (!groups[key]) groups[key] = [];
        groups[key].push(e.val);
      });
      const groupAvgs = Object.values(groups).map(g => g.reduce((a, b) => a + b, 0) / g.length);
      if (groupAvgs.length < 2) return null; // グループが1つしかない場合は計算不可
      return Math.max(...groupAvgs) - Math.min(...groupAvgs);
    }
    default: return null;
  }
};

// --- Voice Assistant Utilities ---
// iOS Safari: speechSynthesisはユーザージェスチャーで一度アンロックが必要
let ttsUnlocked = false;
const unlockTTSForIOS = () => {
  if (ttsUnlocked || !window.speechSynthesis) return;
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  if (!isIOS) { ttsUnlocked = true; return; }
  const u = new SpeechSynthesisUtterance('');
  u.volume = 0;
  u.lang = 'ja-JP';
  window.speechSynthesis.speak(u);
  ttsUnlocked = true;
};
// iOS Safari: speechSynthesisが15秒でポーズするバグ対策
let iosResumeInterval = null;
const startIOSResumeFix = () => {
  if (iosResumeInterval) return;
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  if (!isIOS) return;
  iosResumeInterval = setInterval(() => {
    if (window.speechSynthesis?.speaking) window.speechSynthesis.resume();
  }, 5000);
};
const stopIOSResumeFix = () => {
  if (iosResumeInterval) { clearInterval(iosResumeInterval); iosResumeInterval = null; }
};

const speak = (text, onEnd, options = {}) => {
  if (!window.speechSynthesis) { onEnd?.(); return; }
  window.speechSynthesis.cancel();
  startIOSResumeFix();
  const doSpeak = () => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'ja-JP';
    utterance.rate = options.rate || 1.1;
    utterance.volume = options.volume ?? 1.0;
    // Use specified voice or find a Japanese voice
    if (options.voice) {
      utterance.voice = options.voice;
    } else if (options.voiceName) {
      const voices = window.speechSynthesis.getVoices();
      const found = voices.find(v => v.name === options.voiceName);
      if (found) utterance.voice = found;
      else {
        const jaVoice = voices.find(v => v.lang.startsWith('ja'));
        if (jaVoice) utterance.voice = jaVoice;
      }
    } else {
      const voices = window.speechSynthesis.getVoices();
      const jaVoice = voices.find(v => v.lang.startsWith('ja'));
      if (jaVoice) utterance.voice = jaVoice;
    }
    if (onEnd) utterance.onend = onEnd;
    utterance.onerror = () => { console.warn('Speech error for:', text); onEnd?.(); };
    window.speechSynthesis.speak(utterance);
  };
  // Voices may not be loaded yet
  if (window.speechSynthesis.getVoices().length === 0) {
    window.speechSynthesis.onvoiceschanged = () => { doSpeak(); window.speechSynthesis.onvoiceschanged = null; };
    // Fallback if voices never load
    setTimeout(() => { if (window.speechSynthesis.getVoices().length === 0) { doSpeak(); } }, 500);
  } else {
    doSpeak();
  }
};

let isSpeakingTTS = false;
const speakAsync = (text, options = {}) => new Promise(resolve => {
  isSpeakingTTS = true;
  speak(text, () => { isSpeakingTTS = false; resolve(); }, options);
});

// TTS再生が終わるまで待つ
const waitForTTSEnd = () => new Promise(resolve => {
  if (!isSpeakingTTS) { resolve(); return; }
  const check = setInterval(() => {
    if (!isSpeakingTTS) { clearInterval(check); setTimeout(resolve, 300); } // 300ms余裕
  }, 100);
  // 最大5秒で強制解除
  setTimeout(() => { clearInterval(check); isSpeakingTTS = false; resolve(); }, 5000);
});

const listenOnce = async (options = {}) => {
  // TTS再生中なら終わるまで待つ（自分の声を拾わないように）
  await waitForTTSEnd();

  return new Promise((resolve) => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
      if (options.onError) options.onError(isIOS
        ? '音声認識非対応: iOS/iPadOSではSafariの最新版（iOS 14.5以上）が必要です'
        : 'このブラウザは音声認識に対応していません（Chrome/Edgeを使用してください）');
      resolve(null); return;
    }
    const recognition = new SR();
    recognition.lang = 'ja-JP';
    recognition.continuous = false;
    recognition.interimResults = true;
    let resolved = false;
    const timeout = options.timeout || 10000;
    const timer = setTimeout(() => {
      if (!resolved) { resolved = true; try { recognition.stop(); } catch {} resolve(options.defaultValue ?? null); }
    }, timeout);
    recognition.onaudiostart = () => {
      if (options.onListening) options.onListening();
    };
    recognition.onresult = (event) => {
      const last = event.results[event.results.length - 1];
      if (last.isFinal) {
        if (!resolved) { resolved = true; clearTimeout(timer); resolve(last[0].transcript); }
      } else {
        if (options.onInterim) options.onInterim(last[0].transcript);
      }
    };
    recognition.onerror = (e) => {
      console.warn('[listenOnce] error:', e.error, e.message);
      if (e.error === 'not-allowed') {
        if (options.onError) options.onError('マイクの使用が許可されていません。アドレスバーの🔒→サイトのアクセス許可→マイク→許可');
      } else if (e.error === 'no-speech') {
        // 無音 - 正常
      } else if (e.error === 'aborted') {
        // 中断 - 正常
      } else if (e.error === 'network') {
        if (options.onError) options.onError('音声認識サービスに接続できません。インターネット接続を確認してください');
      } else {
        if (options.onError) options.onError(`音声認識エラー: ${e.error}`);
      }
      if (!resolved) { resolved = true; clearTimeout(timer); resolve(null); }
    };
    recognition.onend = () => { console.log('[listenOnce] onend, resolved:', resolved); if (!resolved) { resolved = true; clearTimeout(timer); resolve(options.defaultValue ?? null); } };
    try {
      recognition.start();
      console.log('[listenOnce] recognition.start() called, timeout:', timeout);
    } catch(e) {
      console.warn('Speech start failed:', e);
      if (options.onError) options.onError('音声認識の開始に失敗しました');
      resolve(null);
    }
  });
};

// Default voice command mappings
const DEFAULT_VOICE_COMMANDS = [
  { id: 'yes', label: 'はい（確認）', keywords: 'はい,うん,OK,オーケー,そう,イエス,yes', description: '確認・肯定の応答' },
  { id: 'no', label: 'いいえ（否定）', keywords: 'いいえ,いや,ダメ,違う,ノー,no', description: '否定の応答' },
  { id: 'complete', label: '完了', keywords: '完了,かんりょう,終わり,おわり,done', description: '現在の作業を完了' },
  { id: 'interrupt', label: '中断（一時停止）', keywords: '中断,ちゅうだん,止め,やめ,ストップ,stop', description: '作業時間の計測を一時停止/再開' },
  { id: 'next', label: '次へ', keywords: '次,つぎ,next', description: '次の工程/台に進む' },
  { id: 'measurement', label: '測定入力', keywords: '測定入力,測定開始,そくてい', description: '測定の音声入力を開始' },
  { id: 'sequential', label: '通常モード', keywords: '通常,じゅんじょ,順序,ノーマル', description: '通常（順序）モードを選択' },
  { id: 'custom', label: 'カスタムモード', keywords: 'カスタム,自由,じゆう', description: 'カスタムモードを選択' },
  { id: 'batch', label: 'まとめて', keywords: 'まとめ,一括,バッチ', description: 'まとめて開始/完了' },
  { id: 'allComplete', label: '全作業完了', keywords: '全部完了,全作業完了,すべて完了', description: '全工程を完了する' },
];

// Build matcher from voice commands config
const buildVoiceMatcher = (voiceCommands) => {
  const map = {};
  const cmds = voiceCommands || DEFAULT_VOICE_COMMANDS;
  cmds.forEach(cmd => {
    const words = cmd.keywords.split(',').map(w => w.trim()).filter(Boolean);
    const pattern = new RegExp(words.map(w => w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'), 'i');
    map[cmd.id] = (text) => {
      if (!text) return false;
      return pattern.test(text) || pattern.test(normalizeVoiceText(text));
    };
  });
  return map;
};

// Fallback matchers (used when no settings loaded) - normalize input
const isYesResponse = (text) => { const t = normalizeVoiceText(text); return /はい|うん|OK|オーケー|そう|イエス|yes/i.test(t); };
const isNoResponse = (text) => { const t = normalizeVoiceText(text); return /いいえ|いや|ダメ|違う|ノー|no/i.test(t); };
const isCompleteCmd = (text) => { const t = normalizeVoiceText(text); return /完了|かんりょう|終わり|おわり|done/i.test(t); };
const isInterruptCmd = (text) => { const t = normalizeVoiceText(text); return /中断|ちゅうだん|止め|やめ|ストップ|stop/i.test(t); };
const isNextCmd = (text) => { const t = normalizeVoiceText(text); if (/次工程|次の工程/i.test(t)) return false; return /^(次|つぎ|next)$/i.test(t?.trim()) || /次へ|つぎへ/i.test(t); };
const isNextStepCmd = (text) => { const t = normalizeVoiceText(text); return /次工程|次の工程|つぎこうてい|つぎのこうてい/i.test(t); };
const isCancelCmd = (text) => { const t = normalizeVoiceText(text); return /キャンセル|取り消し|とりけし|cancel/i.test(t); };

// 同ロット内の他工程の測定結果を1つのオブジェクトにまとめる (cross-step 参照用)
// 戻り値: { [入力ID または 計算ID]: 値 } — 現在の工程と ID 衝突する場合は現工程優先
// ID 衝突を避けたい場合は `stepタイトル_変数名` の形式でも引けるよう、両方の形式を入れる
// 同ロット内 他工程の測定結果を「数式から参照可能な変数」として収集する。
// 出力:
//  - bare ID (k, calc.id): 後方互換 (既存式は無修正で動く)。衝突時は先勝ち。
//  - prefixed ID (${stepId}_${k}, ${stepId}_${calc.id}): 衝突しない一意のID。新規式はこちらを推奨。
const collectCrossStepValues = (lot, currentStepId) => {
  if (!lot || !lot.steps || !lot.measurementResults) return {};
  const out = {};
  lot.steps.forEach(step => {
    if (!step || step.id === currentStepId) return; // 現工程は除外
    const cfg = step.measurementConfig;
    if (!cfg) return;
    const inputVals = lot.measurementResults[`${step.id}-0-values`]
      || lot.measurementResults[`${step.id}-values`]
      || {};
    const resultData = lot.measurementResults[`${step.id}-0`]
      || lot.measurementResults[`${step.id}-result`];
    const calcResults = resultData?.calcResults || [];
    Object.entries(inputVals).forEach(([k, v]) => {
      const num = Number(v);
      if (!Number.isFinite(num)) return;
      if (out[k] === undefined) out[k] = num; // bare (後方互換、先勝ち)
      out[`${step.id}_${k}`] = num;            // prefixed (衝突回避)
    });
    calcResults.forEach(cr => {
      if (cr?.id && Number.isFinite(cr.result)) {
        if (out[cr.id] === undefined) out[cr.id] = cr.result;
        out[`${step.id}_${cr.id}`] = cr.result;
      }
    });
  });
  return out;
};

// 計算チェーン: 計算は順番に評価され、前の計算結果は後続の計算で変数として使える。
// extraValues に他工程の計算結果を渡すと、数式参照で利用可能。
const calculateMeasurementResults = (values, config, extraValues = {}) => {
  const calculations = config.calculations || [{
    id: 'default',
    label: '計算結果',
    method: config.calculation,
    formula: config.formula,
    inputIds: [],
    toleranceUpper: config.toleranceUpper,
    toleranceLower: config.toleranceLower,
    unit: config.unit
  }];

  // 累積コンテキスト: 通常入力 + 他工程結果 + 計算済みの値
  const ctx = { ...extraValues, ...values };

  return calculations.map(calc => {
    // inputIds に含まれる ID は「通常入力 ID」または「同工程の前の計算 ID」の両方を許可
    let relevantInputs;
    if (calc.inputIds?.length > 0) {
      // 通常入力からマッチするもの
      const inputMatches = config.inputs.filter(inp => calc.inputIds.includes(inp.id));
      // 計算 ID からマッチするもの (前に計算済みのみ)
      const calcMatches = calc.inputIds
        .filter(id => !config.inputs.some(inp => inp.id === id) && ctx[id] !== undefined)
        .map(id => ({ id, label: id })); // 仮想入力として扱う
      relevantInputs = [...inputMatches, ...calcMatches];
    } else {
      relevantInputs = config.inputs;
    }
    const result = calculateSingleResult(ctx, relevantInputs, calc);
    // この計算結果を次の計算で参照可能にする
    if (result !== null && !isNaN(result)) {
      ctx[calc.id] = result;
    }
    // 公差判定:
    // - toleranceEnabled === false → 判定なし (記録のみ)
    // - nominal がある場合: 範囲 = nominal + [toleranceLower, toleranceUpper]
    // - nominal が無い場合: 既存挙動 (公差を絶対値として扱う)
    const toleranceEnabled = calc.toleranceEnabled !== false; // 未指定 or true で判定ON (後方互換)
    const nominal = Number.isFinite(Number(calc.nominal)) ? Number(calc.nominal) : 0;
    let isOk = null;
    let lowerLimit = null, upperLimit = null;
    if (result !== null && toleranceEnabled) {
      lowerLimit = nominal + (calc.toleranceLower ?? -Infinity);
      upperLimit = nominal + (calc.toleranceUpper ?? Infinity);
      isOk = result >= lowerLimit && result <= upperLimit;
    }
    return { ...calc, result, isOk, nominal, toleranceEnabled, lowerLimit, upperLimit };
  });
};

// 矢印比較を評価: 2つの値 (入力 or 計算結果) を比較し、1つの矢印を 1箇所に表示
// 戻り値: arrows ごとに { pos, dir: 'up'|'down'|'equal'|null, valA, valB, diff, label }
// pos は { x, y } in % (表示位置)
const evaluateArrows = (config, values, calcResults, extraValues = {}) => {
  const arrows = config?.arrows || [];
  if (arrows.length === 0) return [];
  const inputs = config?.inputs || [];
  // 全ての参照可能な値を統合
  const calcMap = {};
  (calcResults || []).forEach(cr => { if (cr?.id) calcMap[cr.id] = cr.result; });
  const allValues = { ...extraValues, ...values, ...calcMap };

  return arrows.map(arr => {
    const valA = Number(allValues[arr.sourceA]);
    const valB = Number(allValues[arr.sourceB]);
    // 表示位置の決定 (優先順位):
    //  1) 明示的に position が指定されていれば、それを使う
    //  2) sourceA と sourceB が両方とも入力ポイント (inputs に存在) なら、その中点
    //  3) どちらか一方だけ入力ポイントなら、その位置
    //  4) どれも該当しなければ中央 (50, 50)
    // ※ 以前は (1) → (4) しか無く、複数の矢印に position が無いと全部 (50, 50)
    //    に重なって表示されていた (拡大測定画面で 1 本しか見えないバグ)。
    let pos = arr.position;
    if (!pos) {
      const inputA = inputs.find(i => i.id === arr.sourceA);
      const inputB = inputs.find(i => i.id === arr.sourceB);
      if (inputA && inputB) pos = { x: (inputA.x + inputB.x) / 2, y: (inputA.y + inputB.y) / 2 };
      else if (inputA) pos = { x: inputA.x, y: inputA.y };
      else if (inputB) pos = { x: inputB.x, y: inputB.y };
      else pos = { x: 50, y: 50 };
    }
    if (!Number.isFinite(valA) || !Number.isFinite(valB)) {
      return { ...arr, pos, valA, valB, dir: null, diff: null };
    }
    const threshold = Number(arr.threshold) || 0;
    const diff = valA - valB;
    let dir;
    if (Math.abs(diff) <= threshold) dir = 'equal';
    else if (diff > 0) dir = 'up';   // A > B → ↗
    else dir = 'down';                // A < B → ↘
    return { ...arr, pos, valA, valB, dir, diff };
  });
};

// 音声テキスト正規化: 誤変換補正 + 全角→半角 + 漢数字→数字
const normalizeVoiceText = (text) => {
  if (!text) return '';
  let t = text;
  // 音声認識の誤変換補正（同音異字）
  const homophones = {
    '皇帝': '工程', '号艇': '工程', '後程': '工程', '高低': '工程', '肯定': '工程', 'こうてい': '工程',
    '交代': '工程', '好転': '工程', '公定': '工程', '行程': '工程', '校庭': '工程', '口頭': '工程',
    '代目': '台目', 'だいめ': '台目', '大目': '台目', '題目': '台目',
    '完了': '完了', 'かんりょう': '完了',
    '中断': '中断', 'ちゅうだん': '中断',
    '測定': '測定', 'そくてい': '測定',
    '次': '次', 'つぎ': '次',
  };
  Object.entries(homophones).forEach(([k, v]) => {
    if (k !== v) t = t.replace(new RegExp(k, 'g'), v);
  });
  // 全角数字→半角
  t = t.replace(/[０-９]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0));
  // 全角英字→半角
  t = t.replace(/[Ａ-Ｚａ-ｚ]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0));
  // 漢数字→半角 (位取り対応: 百/十)
  const kanjiMap = { '零': 0, '〇': 0, '一': 1, '二': 2, '三': 3, '四': 4, '五': 5, '六': 6, '七': 7, '八': 8, '九': 9, '十': 10, '百': 100 };
  // ひらがな数字→半角
  const hiraMap = { 'いち': '1', 'に': '2', 'さん': '3', 'し': '4', 'よん': '4', 'ご': '5', 'ろく': '6', 'なな': '7', 'しち': '7', 'はち': '8', 'きゅう': '9', 'く': '9', 'じゅう': '10' };
  // ひらがな数字→数字 (長い順にマッチ)
  Object.entries(hiraMap).sort((a,b) => b[0].length - a[0].length).forEach(([k, v]) => {
    t = t.replace(new RegExp(k, 'g'), v);
  });
  // 漢数字の位取り変換: 二十三→23, 十五→15 etc
  t = t.replace(/([一二三四五六七八九]?)百([一二三四五六七八九]?十?[一二三四五六七八九]?)/g, (_, h, rest) => {
    let val = (h ? kanjiMap[h] : 1) * 100;
    const tenMatch = rest.match(/([一二三四五六七八九]?)十([一二三四五六七八九]?)/);
    if (tenMatch) {
      val += (tenMatch[1] ? kanjiMap[tenMatch[1]] : 1) * 10;
      if (tenMatch[2]) val += kanjiMap[tenMatch[2]];
    } else {
      // 残り1文字の漢数字
      for (const c of rest) { if (kanjiMap[c] !== undefined && kanjiMap[c] < 10) val += kanjiMap[c]; }
    }
    return String(val);
  });
  t = t.replace(/([一二三四五六七八九]?)十([一二三四五六七八九]?)/g, (_, tens, ones) => {
    return String((tens ? kanjiMap[tens] : 1) * 10 + (ones ? kanjiMap[ones] : 0));
  });
  // 残りの単独漢数字
  t = t.replace(/[零〇一二三四五六七八九]/g, c => String(kanjiMap[c]));
  // 連続数字を結合しない（"1 0" → そのまま）
  return t;
};

const parseJapaneseNumber = (text) => {
  if (!text) return null;
  const norm = normalizeVoiceText(text);
  const direct = norm.replace(/[,\s]/g, '');
  if (/^[+-]?\d+\.?\d*$/.test(direct)) return parseFloat(direct);
  let cleaned = norm.replace(/プラス/g, '+').replace(/マイナス/g, '-').replace(/てん|点/g, '.').replace(/ミリ|mm/g, '');
  const numMatch = cleaned.match(/[+-]?\d+\.?\d*/);
  if (numMatch) return parseFloat(numMatch[0]);
  return null;
};

const getPastMeasurementData = (lots, model, stepId) => {
  const results = [];
  lots.forEach(lot => {
    if (lot.status !== 'completed' || lot.model !== model || !lot.measurementResults) return;
    Object.entries(lot.measurementResults).forEach(([key, result]) => {
      if (key.startsWith(stepId + '-')) results.push(result);
    });
  });
  return results;
};

const getPastInputStats = (pastData, inputId) => {
  const vals = pastData.map(d => d.values?.[inputId]).filter(v => v != null && !isNaN(Number(v))).map(Number);
  if (vals.length === 0) return null;
  return {
    last: vals[vals.length - 1],
    avg: (vals.reduce((a, b) => a + b, 0) / vals.length),
    count: vals.length
  };
};

